    private void BtnCriarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_BtnCriarActionPerformed
        try{
            String path = "c:\\JAVA\\Relatório.txt";
            FileWriter arquivo = new FileWriter(path, false);
            BufferedWriter Escrever = new BufferedWriter(arquivo);
            
            Escrever.write(TextArea.getText());
            Escrever.close();
            arquivo.close();
            
            MessageWindow mensagem = new MessageWindow("Relatório gerado com sucesso!");
            mensagem.setVisible(true);
            
        }catch(IOException e){
            
        }
        
    }//GEN-LAST:event_BtnCriarActionPerformed

