    private void formWindowOpened(java.awt.event.WindowEvent evt) {//GEN-FIRST:event_formWindowOpened
        ArrayList<Aluguel> alugueis = new ArrayList();
        AluguelController.getAluguelPorCliente(cliente,alugueis);    
        
        if(alugueis.size()>0){
            TextArea.setText("---------HISTÓRICO---------\n");
            for(int i=0; i < alugueis.size(); i++){                
                TextArea.setText(TextArea.getText() + "Id do pedido: " + alugueis.get(i).getId() + "\n");
                TextArea.setText(TextArea.getText() + "Cliente: " + cliente.getLogin() + "\n");
                
                ArrayList<Carro> carro = new ArrayList();
                CarroController.getCarroPorId(carro, alugueis.get(i).getId_carro());
                
                TextArea.setText(TextArea.getText() + "Carro: " + carro.get(0).getModelo() + " - " + carro.get(0).getCor() + "\n");
                TextArea.setText(TextArea.getText() + "Preço: R$ " + alugueis.get(i).getPreco() + "\n");
                TextArea.setText(TextArea.getText() + "Data Inicial: " + alugueis.get(i).getData_inicial() + "\n");
                TextArea.setText(TextArea.getText() + "Data Final: " + alugueis.get(i).getData_final() + "\n");
                TextArea.setText(TextArea.getText() + "----------------------------------\n");
            }
        }else{
            TextArea.setText("Não há histórico de pedidos.");
        }
    }//GEN-LAST:event_formWindowOpened

